namespace Elsa.Persistence.VNext.Document;

public class DocumentDatabasePlanner : IPersistenceSchemaPlanner<DocumentDatabasePlan>
{
    public DocumentDatabasePlan Plan(PersistenceSchema schema)
    {
        var collections = schema.StorageUnits.Select(PlanCollection).ToList();
        return new DocumentDatabasePlan(collections);
    }

    private static DocumentCollection PlanCollection(PersistenceStorageUnit storageUnit)
    {
        var fields = storageUnit.Fields
            .Select(field => new DocumentField(field.Name, field.Type, field.IsNullable))
            .ToList();
        var indexes = storageUnit.Indexes
            .Select(index => new DocumentIndex(index.Name, storageUnit.Name, storageUnit.Namespace, index.Columns, index.IsUnique))
            .ToList();
        var keyFields = storageUnit.Key?.Columns ?? [];

        return new DocumentCollection(storageUnit.Name, storageUnit.Namespace, fields, keyFields, indexes);
    }
}

using Elsa.Persistence.VNext;

namespace Elsa.Persistence.VNext.Physicalization;

public static class PhysicalizationPolicyValidator
{
    public static PersistenceStorageUnit GetStorageUnit(PersistenceSchema schema, StoragePhysicalizationPolicy policy)
    {
        var storageUnit = schema.StorageUnits.SingleOrDefault(x => x.Name == policy.StorageUnit);

        if (storageUnit == null)
            throw new InvalidOperationException($"Storage unit '{policy.StorageUnit}' was not declared by schema '{schema.Name}'.");

        var fields = storageUnit.Fields.Select(x => x.Name).ToHashSet(StringComparer.Ordinal);

        foreach (var index in policy.Indexes)
        {
            var missingField = index.Fields.FirstOrDefault(field => !fields.Contains(field));

            if (missingField != null)
                throw new InvalidOperationException($"Physicalized index '{index.Name}' references undeclared field '{missingField}' on storage unit '{storageUnit.Name}'.");
        }

        return storageUnit;
    }
}

namespace Elsa.Resilience;

public class ResilienceStrategyCatalog : IResilienceStrategyCatalog
{
    private readonly Lazy<Task<IEnumerable<IResilienceStrategy>>> _strategies;
    private readonly IEnumerable<IResilienceStrategySource> _providers;

    public ResilienceStrategyCatalog(IEnumerable<IResilienceStrategySource> providers)
    {
        _providers = providers;
        _strategies = new(GetStrategiesInternalAsync, LazyThreadSafetyMode.ExecutionAndPublication);
    }

    public Task<IEnumerable<IResilienceStrategy>> ListAsync(CancellationToken cancellationToken = default)
    {
        return _strategies.Value;
    }

    public async Task<IResilienceStrategy?> GetAsync(string id, CancellationToken cancellationToken = default)
    {
        var strategies = await ListAsync(cancellationToken);
        return strategies.FirstOrDefault(x => x.Id == id);
    }

    private async Task<IEnumerable<IResilienceStrategy>> GetStrategiesInternalAsync()
    {
        var strategies = new List<IResilienceStrategy>();
        foreach (var provider in _providers) strategies.AddRange(await provider.GetStrategiesAsync());
        return strategies;
    }
}
